import React, { useState, useEffect } from 'react'
import { Row, Col, Button, Space, message, } from 'antd';
import Api from '../../helpers/api';

import {
    SaveOutlined,
    ArrowLeftOutlined,
    ReloadOutlined,
} from '@ant-design/icons';
import TableMaterialVendor from './TableMaterialVendor';
import TableMaterialRoom from './TableMaterialRoom';
import handleApiError from '../../helpers/handleApiError';

const api = new Api();

const authobjectCfg = {
    approve: 'reservation-approve',
    reject: 'reservation-reject',
}

const FormMaterial = (props) => {

    const [errors, setErrors] = useState({})
    const [loading, setLoading] = useState(false)
    const [selectedMaterial, setSelectedMaterial] = useState([])
    const [quantity, setQuantity] = useState([])

    const { formData, view } = props

    useEffect(() => {
        if (formData.details) {
            setSelectedMaterial(formData.details)
        }
    }, [formData])

    const handleChangeQuantity = (value) => {
        setQuantity(value)
    }

    const handleSubmit = () => {
        selectedMaterial.map((item, index) => {
            selectedMaterial[index].reservation_id = formData.response.id
            selectedMaterial[index].quantity = quantity[item.id] ? quantity[item.id] : 0

            if (selectedMaterial[index]['material']) {
                selectedMaterial[index].id = selectedMaterial[index].material.id
            }
        })

        let data = { materials: selectedMaterial }
        let apiPost = api.storeReservationDetail(data)

        setLoading(true)
        apiPost.then(response => {
            console.log(response)
            setLoading(false)
            message.success('save data success');
            props.history.goBack();
        }).catch(error => {
            setLoading(false)
            if (error.response && error.response.data) {
                const { errors } = error.response.data
                setErrors(errors)
            }
            handleApiError(error, props)
        });
    }

    const handleReset = () => {
        setQuantity([])
    }

    return (
        <Space direction="vertical" size="large" style={{ width: '100%' }}>
            {errors &&
                <Row>
                    <Col xs={24} sm={24} md={24} lg={24} xl={24}>
                        <div className="ant-form-item-explain ant-form-item-explain-error">
                            <div role="alert">
                                {Object.values(errors)}
                            </div>
                        </div>
                    </Col>
                </Row>
            }
            <Row>
                <Col xs={24} sm={24} md={24} lg={24} xl={24}>

                    {formData.type === 0
                        ?
                        <TableMaterialVendor
                            {...props}
                            selectedMaterial={selectedMaterial}
                            handleChangeQuantity={handleChangeQuantity}
                            selectedMaterialDelete={[]} />
                        :
                        <TableMaterialRoom
                            {...props}
                            selectedMaterial={selectedMaterial}
                            handleChangeQuantity={handleChangeQuantity}
                            selectedMaterialDelete={[]} />
                    }
                </Col>
            </Row>

            <Space>
                <Button onClick={() => props.history.goBack()}
                    icon={<ArrowLeftOutlined />}
                >Back</Button>

                {view ??
                    <>
                        <Button
                            onClick={() => handleReset()}
                            icon={<ReloadOutlined />}
                        >Reset</Button>

                        <Button type="primary" htmlType="submit"
                            onClick={handleSubmit}
                            loading={loading}
                            icon={<SaveOutlined />}
                        >Save</Button>
                    </>
                }
            </Space>
        </Space>
    )
}

export default FormMaterial;